class Solution {
    public boolean isSubstringPresent(String s) {
        for (int i = 0; i < s.length() - 1; i++) {
            String substring = s.substring(i, i + 2);
            if (s.substring(s.length() - 2).contains(substring)) {
                return true;
            }
        }
        return false;
    }
}
